// Compute yesterday's date range in Asia/Manila time (UTC+8)
const formatter = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Manila',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});

const now = new Date();
const yesterdayDate = new Date(now);
yesterdayDate.setDate(now.getDate() - 1);

const yesterdayStr = formatter.format(yesterdayDate); // e.g. 2024-05-20
const todayStr = formatter.format(now);               // e.g. 2024-05-21

// Epoch ms boundaries for Umami API (Manila midnight = UTC-8h offset, Manila is +8)
const startAt = new Date(`${yesterdayStr}T00:00:00+08:00`).getTime();
const endAt   = new Date(`${yesterdayStr}T23:59:59+08:00`).getTime();

return [{ json: { startAt, endAt, date: yesterdayStr, today: todayStr } }];

const umami = $('Umami — Website Stats').item.json;
const supabaseRaw = $('Supabase — New Leads').item.json;
const leads = Array.isArray(supabaseRaw) ? supabaseRaw : [];
const dateStr = $('Get Date Range').item.json.date;

// Umami stats
const visitors  = umami.visitors?.value  ?? 0;
const pageviews = umami.pageviews?.value ?? 0;
const visits    = umami.visits?.value    ?? 0;
const bounces   = umami.bounces?.value   ?? 0;

// Leads breakdown
const newLeads  = leads.length;
const confirmed = leads.filter(l => l.status === 'Confirmed').length;
const showed    = leads.filter(l => l.status === 'Showed Up').length;
const noShow    = leads.filter(l => l.status === 'No Show').length;
const lost      = leads.filter(l => l.status === 'Lost').length;
const pending   = leads.filter(l => l.status === 'Booked').length;

const convRate = visitors > 0 ? ((newLeads / visitors) * 100).toFixed(1) : '0.0';

const subject = `Kimut Clinic — Daily Digest ${dateStr}`;
const html = `
<div style="font-family:sans-serif;max-width:600px;margin:0 auto">
  <h2 style="color:#1a1a2e">Kimut Clinic Daily Report</h2>
  <p style="color:#666">${dateStr}</p>

  <h3 style="color:#4a4a8a">Website Traffic</h3>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:6px 0">Unique Visitors</td><td style="text-align:right"><strong>${visitors}</strong></td></tr>
    <tr><td style="padding:6px 0">Page Views</td><td style="text-align:right"><strong>${pageviews}</strong></td></tr>
    <tr><td style="padding:6px 0">Sessions</td><td style="text-align:right"><strong>${visits}</strong></td></tr>
    <tr><td style="padding:6px 0">Bounces</td><td style="text-align:right"><strong>${bounces}</strong></td></tr>
  </table>

  <h3 style="color:#4a4a8a">Leads (submitted yesterday)</h3>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:6px 0">New Leads</td><td style="text-align:right"><strong>${newLeads}</strong></td></tr>
    <tr><td style="padding:6px 0">Confirmed</td><td style="text-align:right">${confirmed}</td></tr>
    <tr><td style="padding:6px 0">Showed Up</td><td style="text-align:right">${showed}</td></tr>
    <tr><td style="padding:6px 0">No Show</td><td style="text-align:right">${noShow}</td></tr>
    <tr><td style="padding:6px 0">Lost</td><td style="text-align:right">${lost}</td></tr>
    <tr><td style="padding:6px 0">Pending (Booked)</td><td style="text-align:right">${pending}</td></tr>
  </table>

  <h3 style="color:#4a4a8a">Conversion</h3>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:6px 0">Traffic → Booking Rate</td><td style="text-align:right"><strong>${convRate}%</strong></td></tr>
  </table>
</div>
`.trim();

return [{ json: { subject, html } }];
